import { Command } from "commander";
import pc from "picocolors";
import { getStreamUrl } from "../lib/api.js";
import { getConfig } from "../lib/config.js";
import { connectSSE } from "../lib/sse.js";

interface SourceEventNotification {
  payloadId: number;
  sourceEvent: {
    provider: string;
    eventType: string;
    sourceId: string;
    title: string;
    occurredAt: string;
  };
}

interface CatchUpEvent {
  catchUp: true;
  deliveryId: string;
  eventType: string;
  payloadId: number;
  receivedAt: number;
  source: string;
}

export const listenCommand = new Command("listen")
  .description("Stream real-time webhook events")
  .option("--json", "Output raw JSON events")
  .action(async (opts: { json?: boolean }) => {
    const config = getConfig();
    if (!config) {
      console.log(pc.red("  Not logged in. Run `lightfast login` first."));
      process.exit(1);
    }

    console.log(`  Listening for events in ${pc.bold(config.orgName)}...`);
    console.log(pc.dim("  Press Ctrl+C to stop."));
    console.log();

    const controller = new AbortController();
    process.on("SIGINT", () => {
      console.log();
      controller.abort();
    });

    await connectSSE({
      url: getStreamUrl(),
      token: config.apiKey,
      signal: controller.signal,
      onConnect: () => {
        console.log(pc.green("  Connected."));
      },
      onDisconnect: (reason) => {
        console.log(pc.yellow(`  ${reason}`));
      },
      onEvent: (event) => {
        if (event.event === "connected") {
          return;
        }

        if (event.event !== "event") {
          return;
        }

        const data = JSON.parse(event.data) as
          | SourceEventNotification
          | CatchUpEvent;

        if (opts.json) {
          console.log(JSON.stringify(data));
          return;
        }

        // Catch-up events have lightweight shape
        if ("catchUp" in data) {
          const e = data;
          const time = new Date(e.receivedAt).toLocaleTimeString();
          const source = colorProvider(e.source);
          console.log(
            `  ${pc.dim(time)}  ${source}  ${pc.bold(e.eventType)}  ${pc.dim(`#${e.payloadId}`)}`
          );
          return;
        }

        // Real-time events have full PostTransformEvent
        const e = data;
        const time = new Date(e.sourceEvent.occurredAt).toLocaleTimeString();
        const source = colorProvider(e.sourceEvent.provider);
        console.log(
          `  ${pc.dim(time)}  ${source}  ${pc.bold(e.sourceEvent.eventType)}  ${e.sourceEvent.title}`
        );
      },
    });
  });

function colorProvider(p: string): string {
  switch (p) {
    case "github":
      return pc.white(p);
    case "vercel":
      return pc.cyan(p);
    case "linear":
      return pc.magenta(p);
    case "sentry":
      return pc.red(p);
    default:
      return pc.gray(p);
  }
}
import select from "@inquirer/select";
import { Command } from "commander";
import open from "open";
import ora from "ora";
import pc from "picocolors";
import { listOrganizations, setupOrg } from "../lib/api.js";
import { startAuthServer } from "../lib/auth-server.js";
import { getBaseUrl, getConfig, saveConfig } from "../lib/config.js";

export const loginCommand = new Command("login")
  .description("Authenticate with Lightfast and select an organization")
  .action(async () => {
    const existing = getConfig();
    if (existing && existing.orgName !== "env") {
      console.log(`  Currently linked to: ${pc.bold(existing.orgName)}`);
      console.log();
    }

    // Step 1: Start localhost server
    const { port, state, waitForToken } = await startAuthServer();
    const authUrl = `${getBaseUrl()}/cli/auth?port=${port}&state=${encodeURIComponent(state)}`;

    console.log("  Opening browser to authenticate...");
    console.log(pc.dim(`  If it doesn't open, visit: ${authUrl}`));
    console.log();

    try {
      await open(authUrl);
    } catch {
      // Browser didn't open — user will use the URL manually
    }

    // Step 2: Wait for JWT callback
    const authSpinner = ora("Waiting for authentication...").start();
    const { token: jwt } = await waitForToken();
    authSpinner.succeed("Authenticated!");
    console.log();

    // Step 3: List organizations
    const orgSpinner = ora("Fetching organizations...").start();
    let orgs: Awaited<ReturnType<typeof listOrganizations>>;
    try {
      orgs = await listOrganizations(jwt);
    } catch {
      orgSpinner.fail("Failed to fetch organizations. Please try again.");
      process.exit(1);
    }
    orgSpinner.stop();

    if (orgs.length === 0) {
      console.log(
        pc.yellow("  No organizations found. Create one at lightfast.ai first.")
      );
      process.exit(1);
    }

    // Step 4: Interactive org selection
    const selectedOrgId = await select({
      message: "Which organization?",
      choices: orgs.map((org) => ({
        name: `${org.name} (${org.slug})`,
        value: org.id,
      })),
    });

    // Step 5: Create API key
    const setupSpinner = ora("Setting up...").start();
    let result: Awaited<ReturnType<typeof setupOrg>>;
    try {
      result = await setupOrg(jwt, selectedOrgId);
    } catch {
      setupSpinner.fail("Session expired. Please run `lightfast login` again.");
      process.exit(1);
    }
    setupSpinner.succeed(`Linked to ${pc.bold(result.orgName)}!`);

    // Step 6: Save config
    saveConfig({
      orgId: result.orgId,
      orgSlug: result.orgSlug,
      orgName: result.orgName,
      apiKey: result.apiKey,
    });

    console.log();
    console.log(
      `  Run ${pc.cyan("lightfast listen")} to stream webhook events.`
    );
  });
import { Command } from "commander";
import { clearConfig, getConfig } from "../lib/config.js";

export const logoutCommand = new Command("logout")
  .description("Clear credentials and unlink organization")
  .action(() => {
    const config = getConfig();
    if (!config) {
      console.log("Not logged in.");
      return;
    }
    clearConfig();
    console.log("Logged out.");
  });

